command:
// =========================
// HAMLET GENERATOR
// Sandbox Generator
// =========================

function roll(sides) {
    return Math.ceil(Math.random() * sides);
}

// -------------------------
// SETTLEMENT NAME
// -------------------------

let settlementName = "Unknown Hamlet";
let settlementNameFormat = "";
let settlementNameRolls = [];

if (!globalThis.isGeneratingSettlementName) {
    const nameMacro = game.macros.getName("Settlement Name Generator");

    if (nameMacro) {
        globalThis.isGeneratingSettlementName = true;

        await nameMacro.execute();

        globalThis.isGeneratingSettlementName = false;

        settlementName =
        globalThis.generatedSettlementName ?? "Unknown Hamlet";

        settlementNameFormat =
        globalThis.generatedSettlementNameFormat ?? "";

        settlementNameRolls =
        globalThis.generatedSettlementNameRolls ?? [];
    }
}
// -------------------------
// TABLES
// -------------------------

const mainBuildings = [
    "Brewery/Vineyard",
"Chapel",
"Farm/Ranch",
"Manor",
"Mill",
"Mine",
"Sawmill",
"Shop",
"Tavern",
"Toll",
"Tourney grounds",
"Watchtower"
];

const buildingDescriptions = {
    "Brewery/Vineyard": "A small production site for ale, beer, wine, or local spirits. It may attract workers, merchants, and travelers.",
    "Chapel": "A small religious building serving locals, travelers, or a minor holy site.",
    "Farm/Ranch": "The hamlet centers around food production, livestock, crops, or grazing land.",
    "Manor": "A minor noble, wealthy landholder, or important family controls the hamlet from here.",
    "Mill": "A working mill processes grain, lumber, or another local resource.",
    "Mine": "The settlement exists because of a nearby mine or mineral source.",
    "Sawmill": "The hamlet cuts and prepares timber, usually near woods or a river.",
    "Shop": "A small trade stop or general store serves nearby locals and travelers.",
    "Tavern": "The hamlet exists around an inn, tavern, or roadside drinking house.",
    "Toll": "A guarded toll point controls a road, bridge, ford, or pass.",
    "Tourney grounds": "A field or small arena used for contests, training, or noble games.",
    "Watchtower": "A lookout or defensive post watches the road, border, monster territory, or wilderness."
};

const layouts = [
    "Clustered around the main building",
"Lined up along a road",
"Scattered loosely around the area"
];

const layoutDescriptions = {
    "Clustered around the main building": "The hamlet feels tight and centered. Most activity happens near the main building.",
    "Lined up along a road": "The hamlet is built along a path, road, river crossing, or trade route.",
    "Scattered loosely around the area": "Buildings are spread out, making the hamlet feel rural, quiet, or exposed."
};

const dispositions = [
    { min: 2, max: 2, result: "Attack on sight" },
{ min: 3, max: 5, result: "Hostile" },
{ min: 6, max: 8, result: "Neutral" },
{ min: 9, max: 11, result: "Welcoming" },
{ min: 12, max: 12, result: "Enthusiastic" }
];

const dispositionDescriptions = {
    "Attack on sight": "The inhabitants immediately treat outsiders as enemies.",
    "Hostile": "The locals are unfriendly, suspicious, or openly threatening.",
    "Neutral": "The locals are cautious but not immediately aggressive.",
    "Welcoming": "The inhabitants are friendly and willing to talk or trade.",
    "Enthusiastic": "The locals are very pleased to see travelers and may offer help."
};

const secrets = [
    "Cannibals",
"Cultists",
"Doppelgangers",
"Inbred",
"Lycanthropes/Vampires",
"Murderers"
];

const secretDescriptions = {
    "Cannibals": "The inhabitants secretly eat people, possibly travelers, prisoners, or outsiders.",
    "Cultists": "The hamlet hides forbidden worship, rituals, or loyalty to a dark power.",
    "Doppelgangers": "Some or all inhabitants are impostors pretending to be normal villagers.",
    "Inbred": "The hamlet is isolated and has disturbing family or social ties.",
    "Lycanthropes/Vampires": "The inhabitants hide a monstrous curse or undead presence.",
    "Murderers": "The locals have killed before and may be hiding evidence, victims, or a pattern of violence."
};

function tableRoll2d6(total) {
    return dispositions.find(row => total >= row.min && total <= row.max).result;
}

// -------------------------
// ROLLS
// -------------------------

let buildingRoll = roll(12);
let mainBuilding = mainBuildings[buildingRoll - 1];

let housesRoll = roll(6);
let peasantHouses = housesRoll - 1;

let layoutRoll = roll(3);
let layout = layouts[layoutRoll - 1];

let dispositionDie1 = roll(6);
let dispositionDie2 = roll(6);
let dispositionTotal = dispositionDie1 + dispositionDie2;
let disposition = tableRoll2d6(dispositionTotal);

let secretCheckRoll = roll(6);
let hasSecret = secretCheckRoll === 1;

let secretRoll = null;
let secret = "None";
let secretDescription = "No hidden secret was generated.";

if (hasSecret) {
    secretRoll = roll(6);
    secret = secrets[secretRoll - 1];
    secretDescription = secretDescriptions[secret];
}

// -------------------------
// OUTPUT
// -------------------------

let output = `
<h2>Hamlet Generator</h2>

<p><b>Name:</b> ${settlementName}</p>
<p><b>Format:</b> ${settlementNameFormat}</p>

<ul>
${settlementNameRolls.map(r => `<li>${r}</li>`).join("")}
</ul>

<hr>

<h3>Main Building</h3>

<p><b>Main Building Roll:</b> d12 = ${buildingRoll}</p>
<p><b>Main Building:</b> ${mainBuilding}</p>
<p><i>${buildingDescriptions[mainBuilding]}</i></p>

<p><b>Peasant Houses Roll:</b> d6 - 1 = ${housesRoll} - 1</p>
<p><b>Peasant Houses:</b> ${peasantHouses}</p>

<hr>

<h3>Layout</h3>

<p><b>Layout Roll:</b> d3 = ${layoutRoll}</p>
<p><b>Layout:</b> ${layout}</p>
<p><i>${layoutDescriptions[layout]}</i></p>

<hr>

<h3>Disposition</h3>

<p><b>Disposition Roll:</b> 2d6 = ${dispositionDie1} + ${dispositionDie2} = ${dispositionTotal}</p>
<p><b>Disposition:</b> ${disposition}</p>
<p><i>${dispositionDescriptions[disposition]}</i></p>

<hr>

<h3>Secret</h3>

<p><b>Secret Check:</b> d6 = ${secretCheckRoll}</p>
<p><b>Has Secret:</b> ${hasSecret ? "Yes" : "No"}</p>
`;

if (hasSecret) {
    output += `
    <p><b>Secret Roll:</b> d6 = ${secretRoll}</p>
    <p><b>Secret:</b> ${secret}</p>
    <p><i>${secretDescription}</i></p>
    `;
} else {
    output += `<p><i>${secretDescription}</i></p>`;
}

output += `
<hr>

<h3>Quick Summary</h3>

<p>
A hamlet centered on a <b>${mainBuilding}</b>, with
<b>${peasantHouses}</b> peasant house${peasantHouses === 1 ? "" : "s"}.
The buildings are <b>${layout.toLowerCase()}</b>.
The inhabitants are <b>${disposition.toLowerCase()}</b>.
${hasSecret ? `Secretly, they are <b>${secret.toLowerCase()}</b>.` : ""}
</p>
`;

ChatMessage.create({
    speaker: ChatMessage.getSpeaker(),
                   content: output
});
